1	"use client";
2	
3	import { useTRPC } from "@repo/app-trpc/react";
4	import type { EntityNotification } from "@repo/app-upstash-realtime";
5	import { useRealtime } from "@repo/app-upstash-realtime/client";
6	import { ENTITY_CATEGORIES } from "@repo/app-validation";
7	import { Button } from "@repo/ui/components/ui/button";
8	import { Input } from "@repo/ui/components/ui/input";
9	import {
10	  Select,
11	  SelectContent,
12	  SelectItem,
13	  SelectTrigger,
14	  SelectValue,
15	} from "@repo/ui/components/ui/select";
16	import {
17	  Table,
18	  TableBody,
19	  TableHead,
20	  TableHeader,
21	  TableRow,
22	} from "@repo/ui/components/ui/table";
23	import { useSuspenseInfiniteQuery } from "@tanstack/react-query";
24	import { Boxes, Search } from "lucide-react";
25	import { useEffect, useMemo, useRef, useState } from "react";
26	import type { Entity } from "~/types";
27	import { EntityRow } from "./entity-row";
28	import { useEntityFilters } from "./use-entity-filters";
29	
30	const CATEGORY_OPTIONS = [
31	  { value: "all", label: "All categories" },
32	  ...ENTITY_CATEGORIES.map((c) => ({ value: c, label: c })),
33	];
34	
35	export function EntitiesTable() {
36	  const { filters, setFilters } = useEntityFilters();
37	  const category = filters.category === "all" ? undefined : filters.category;
38	
39	  // Debounced search
40	  const [searchInput, setSearchInput] = useState(filters.search);
41	  const searchDebounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
42	
43	  useEffect(() => {
44	    if (searchDebounceRef.current) {
45	      clearTimeout(searchDebounceRef.current);
46	    }
47	    searchDebounceRef.current = setTimeout(() => {
48	      void setFilters({ search: searchInput });
49	    }, 300);
50	    return () => {
51	      if (searchDebounceRef.current) {
52	        clearTimeout(searchDebounceRef.current);
53	      }
54	    };
55	  }, [searchInput, setFilters]);
56	
57	  const trpc = useTRPC();
58	
59	  const { data, hasNextPage, isFetchingNextPage, fetchNextPage } =
60	    useSuspenseInfiniteQuery(
61	      trpc.entities.list.infiniteQueryOptions(
62	        {
63	          category,
64	          limit: 30,
65	          search: filters.search || undefined,
66	        },
67	        {
68	          getNextPageParam: (lastPage) => lastPage.nextCursor ?? undefined,
69	        }
70	      )
71	    );
72	
73	  const firstPage = data.pages[0];
74	  const dbEntities = useMemo(
75	    () => data.pages.flatMap((page) => page.entities),
76	    [data.pages]
77	  );
78	
79	  // Live entities — only when on default view (no search, single page)
80	  const [liveEntities, setLiveEntities] = useState<EntityNotification[]>([]);
81	  const isDefaultView = filters.search === "" && data.pages.length <= 1;
82	
83	  // Reset live entities when filters change
84	  const prevFiltersRef = useRef({
85	    category: filters.category,
86	    search: filters.search,
87	  });
88	  useEffect(() => {
89	    const prev = prevFiltersRef.current;
90	    if (prev.category !== filters.category || prev.search !== filters.search) {
91	      setLiveEntities([]);
92	      prevFiltersRef.current = {
93	        category: filters.category,
94	        search: filters.search,
95	      };
96	    }
97	  }, [filters.category, filters.search]);
98	
99	  const { status } = useRealtime({
100	    channels: firstPage?.clerkOrgId ? [`org-${firstPage.clerkOrgId}`] : [],
101	    events: ["org.entity"],
102	    enabled: !!firstPage?.clerkOrgId && isDefaultView,
103	    onData({ data: notification }) {
104	      if (notification.clerkOrgId !== firstPage?.clerkOrgId) {
105	        return;
106	      }
107	      if (category && notification.category !== category) {
108	        return;
109	      }
110	      setLiveEntities((prev) => [notification, ...prev]);
111	    },
112	  });
113	
114	  // Stable set of DB entity externalIds
115	  const dbExternalIds = useMemo(
116	    () => new Set(dbEntities.map((e) => e.externalId)),
117	    [dbEntities]
118	  );
119	
120	  // Merge: live prepend + all pages
121	  const allEntities = useMemo(() => {
122	    const newLive = liveEntities.filter(
123	      (e) => !dbExternalIds.has(e.entityExternalId)
124	    );
125	    const liveAsEntities: Entity[] = newLive.map((e) => ({
126	      id: 0,
127	      externalId: e.entityExternalId,
128	      category: e.category,
129	      key: e.key,
130	      value: e.value,
131	      state: e.state,
132	      url: e.url,
133	      confidence: null,
134	      occurrenceCount: e.occurrenceCount,
135	      lastSeenAt: e.lastSeenAt,
136	      extractedAt: e.lastSeenAt,
137	      createdAt: e.lastSeenAt,
138	    }));
139	    return [...liveAsEntities, ...dbEntities];
140	  }, [liveEntities, dbExternalIds, dbEntities]);
141	
142	  return (
143	    <div className="space-y-4">
144	      {/* Filter bar */}
145	      <div className="flex items-center gap-3">
146	        <div className="relative max-w-sm flex-1">
147	          <Search className="absolute top-1/2 left-3 h-3.5 w-3.5 -translate-y-1/2 text-muted-foreground" />
148	          <Input
149	            className="pl-9"
150	            onChange={(e) => setSearchInput(e.target.value)}
151	            placeholder="Search entities..."
152	            value={searchInput}
153	          />
154	        </div>
155	
156	        <Select
157	          onValueChange={(v) => {
158	            void setFilters({
159	              category: v as typeof filters.category,
160	            });
161	          }}
162	          value={filters.category}
163	        >
164	          <SelectTrigger className="w-[170px]">
165	            <SelectValue />
166	          </SelectTrigger>
167	          <SelectContent>
168	            {CATEGORY_OPTIONS.map((opt) => (
169	              <SelectItem key={opt.value} value={opt.value}>
170	                {opt.label}
171	              </SelectItem>
172	            ))}
173	          </SelectContent>
174	        </Select>
175	
176	        {status === "connected" && isDefaultView && (
177	          <div className="flex items-center gap-1.5 text-muted-foreground text-xs">
178	            <span className="flex h-2 w-2 animate-pulse rounded-full bg-emerald-500" />
179	            Live
180	          </div>
181	        )}
182	      </div>
183	
184	      {/* Table */}
185	      {allEntities.length === 0 ? (
186	        <EmptyState />
187	      ) : (
188	        <div className="overflow-hidden rounded-lg border border-border/60">
189	          <Table>
190	            <TableHeader>
191	              <TableRow>
192	                <TableHead className="w-[120px]">Category</TableHead>
193	                <TableHead>Entity</TableHead>
194	                <TableHead className="w-[100px]">State</TableHead>
195	                <TableHead className="w-[80px] text-center">Seen</TableHead>
196	                <TableHead className="w-[120px] text-right">
197	                  Last active
198	                </TableHead>
199	              </TableRow>
200	            </TableHeader>
201	            <TableBody>
202	              {allEntities.map((entity) => (
203	                <EntityRow entity={entity} key={entity.externalId} />
204	              ))}
205	            </TableBody>
206	          </Table>
207	        </div>
208	      )}
209	
210	      {/* Load more — uses TanStack Query's built-in infinite query state */}
211	      {hasNextPage && allEntities.length > 0 && (
212	        <div className="flex justify-center py-2">
213	          <Button
214	            disabled={isFetchingNextPage}
215	            onClick={() => void fetchNextPage()}
216	            variant="outline"
217	          >
218	            {isFetchingNextPage ? "Loading..." : "Load more"}
219	          </Button>
220	        </div>
221	      )}
222	    </div>
223	  );
224	}
225	
226	function EmptyState() {
227	  return (
228	    <div className="flex flex-col items-center justify-center py-16 text-center">
229	      <div className="mb-4 rounded-full bg-muted/20 p-3">
230	        <Boxes className="h-6 w-6 text-muted-foreground" />
231	      </div>
232	      <p className="font-semibold text-sm">No entities yet</p>
233	      <p className="mt-1 max-w-sm text-muted-foreground text-sm">
234	        Entities will appear here as events are ingested and processed from your
235	        connected sources.
236	      </p>
237	    </div>
238	  );
239	}
